mapper.select:
SELECT p.*, c.name AS category_name, u.store_name AS merchant_name FROM product p LEFT JOIN category c ON p.category_id = c.id LEFT JOIN user u ON p.merchant_id = u.id WHERE p.deleted = 0
AND (p.category_id = #{categoryId} OR p.category_id IN (SELECT id FROM category WHERE parent_id = #{categoryId}))
AND p.name LIKE CONCAT('%', #{keyword}, '%')
AND p.status = #{status}
AND p.merchant_id = #{merchantId}
ORDER BY p.price ASC ORDER BY p.price DESC ORDER BY p.sales DESC ORDER BY p.created_at DESC ORDER BY p.id DESC
